module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);

parameter S0 = 3'b000;
parameter S1 = 3'b001;
parameter S2 = 3'b010;
parameter S3 = 3'b011;
parameter S4 = 3'b100;
parameter S5 = 3'b101;

reg [2:0] current_state, next_state;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        current_state <= S0;
    end else begin
        current_state <= next_state;
    end
end

always @(*) begin
    case(current_state)
        S0: begin
            if(IN == 1'b1) begin
                next_state = S1;
                MATCH = 1'b0;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S1: begin
            if(IN == 1'b0) begin
                next_state = S2;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        S2: begin
            if(IN == 1'b0) begin
                next_state = S3;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        S3: begin
            if(IN == 1'b1) begin
                next_state = S4;
                MATCH = 1'b0;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S4: begin
            if(IN == 1'b1) begin
                next_state = S5;
                MATCH = 1'b1;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S5: begin
            if(IN == 1'b0) begin
                next_state = S2;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
    endcase
end
endmodule
